# ---------------------------------------------------------------------------
# write_input_images
# ---------------------------------------------------------------------------

class TestWriteInputImages:
    def test_single_png(self, work_dir: Path):
        images = [ImageInput(data=TINY_PNG_B64, media_type="image/png")]
        paths = write_input_images(images, work_dir)
        assert len(paths) == 1
        assert paths[0].exists()
        assert paths[0].suffix == ".png"
        assert paths[0].read_bytes() == TINY_PNG_BYTES

    def test_custom_filename(self, work_dir: Path):
        images = [ImageInput(data=TINY_PNG_B64, media_type="image/png", filename="screenshot.png")]
        paths = write_input_images(images, work_dir)
        assert paths[0].name == "screenshot.png"

    def test_multiple_images(self, work_dir: Path):
        images = [
            ImageInput(data=TINY_PNG_B64, media_type="image/png"),
            ImageInput(data=TINY_JPEG_B64, media_type="image/jpeg"),
        ]
        paths = write_input_images(images, work_dir)
        assert len(paths) == 2
        assert paths[0].suffix == ".png"
        assert paths[1].suffix == ".jpg"

    def test_sanitizes_filename(self, work_dir: Path):
        images = [ImageInput(data=TINY_PNG_B64, media_type="image/png", filename="bad/file name!.png")]
        paths = write_input_images(images, work_dir)
        # Should not contain slashes or special chars
        assert "/" not in paths[0].name
        assert "!" not in paths[0].name


# ---------------------------------------------------------------------------
# collect_output_images
# ---------------------------------------------------------------------------

class TestCollectOutputImages:
    def test_collects_png(self, work_dir: Path):
        # Write a PNG file into the output dir
        (work_dir / "result.png").write_bytes(TINY_PNG_BYTES)
        results = collect_output_images(work_dir)
        assert len(results) == 1
        assert results[0].media_type == "image/png"
        assert results[0].filename == "result.png"
        # Round-trip: decoded data matches original
        assert base64.b64decode(results[0].data) == TINY_PNG_BYTES

    def test_empty_dir(self, work_dir: Path):
        results = collect_output_images(work_dir)
        assert results == []

    def test_nonexistent_dir(self):
        results = collect_output_images(Path("/nonexistent/dir"))
        assert results == []

    def test_skips_large_files(self, work_dir: Path):
        # Create a >20MB file (should be skipped)
        big = work_dir / "huge.png"
        big.write_bytes(b"\x00" * (21 * 1024 * 1024))
        results = collect_output_images(work_dir)
        assert len(results) == 0

    def test_multiple_formats(self, work_dir: Path):
        (work_dir / "a.png").write_bytes(TINY_PNG_BYTES)
        (work_dir / "b.jpg").write_bytes(base64.b64decode(TINY_JPEG_B64))
        results = collect_output_images(work_dir)
        assert len(results) == 2
        filenames = {r.filename for r in results}
        assert "a.png" in filenames
        assert "b.jpg" in filenames


