class TestRoundTrip:
    def test_write_then_collect(self, work_dir: Path):
        """Simulates agent receiving images, writing them, then collecting output."""
        # Simulate input images being written
        input_images = [
            ImageInput(data=TINY_PNG_B64, media_type="image/png", filename="input.png"),
        ]
        input_dir = work_dir / "input"
        input_dir.mkdir()
        paths = write_input_images(input_images, input_dir)
        assert len(paths) == 1

        # Simulate agent producing output images
        output_dir = work_dir / "output"
        output_dir.mkdir()
        (output_dir / "generated.png").write_bytes(TINY_PNG_BYTES)

        # Collect output
        output_images = collect_output_images(output_dir)
        assert len(output_images) == 1
        assert output_images[0].filename == "generated.png"
        assert base64.b64decode(output_images[0].data) == TINY_PNG_BYTES


