class TestInjectImageRefs:
    def test_no_images(self):
        assert inject_image_refs("hello", []) == "hello"

    def test_single_image(self, work_dir: Path):
        p = work_dir / "test.png"
        result = inject_image_refs("Review this", [p])
        assert f"[Image: {p}]" in result
        assert result.endswith("Review this")

    def test_multiple_images(self, work_dir: Path):
        paths = [work_dir / "a.png", work_dir / "b.jpg"]
        result = inject_image_refs("prompt", paths)
        assert "[Image:" in result
        assert result.count("[Image:") == 2


