class TestBuildImageFlags:
    def test_no_flag(self, work_dir: Path):
        paths = [work_dir / "a.png"]
        assert build_image_flags(None, paths) == []

    def test_gemini_flag(self, work_dir: Path):
        paths = [work_dir / "a.png", work_dir / "b.png"]
        flags = build_image_flags("-f", paths)
        assert flags == ["-f", str(paths[0]), "-f", str(paths[1])]

    def test_no_paths(self):
        assert build_image_flags("-f", []) == []


