class TestExtractUsageFromEvents:
    def test_result_event(self):
        events = [
            {"type": "text", "content": "hello"},
            {"type": "result", "total_cost_usd": 0.05, "usage": {"input_tokens": 100, "output_tokens": 50}},
        ]
        cost, t_in, t_out = extract_usage_from_events(events)
        assert cost == 0.05
        assert t_in == 100
        assert t_out == 50

    def test_no_result(self):
        cost, t_in, t_out = extract_usage_from_events([{"type": "text"}])
        assert cost is None
        assert t_in is None

    def test_empty(self):
        cost, t_in, t_out = extract_usage_from_events([])
        assert cost is None


class TestParseTokensFromStderr:
    def test_in_out_pattern(self):
        stderr = "Tokens: 1234 in / 567 out"
        t_in, t_out = parse_tokens_from_stderr(stderr)
        assert t_in == 1234
        assert t_out == 567

    def test_input_output_pattern(self):
        stderr = "input_tokens: 500\noutput_tokens: 200"
        t_in, t_out = parse_tokens_from_stderr(stderr)
        assert t_in == 500
        assert t_out == 200

    def test_no_tokens(self):
        t_in, t_out = parse_tokens_from_stderr("no token info here")
        assert t_in is None
        assert t_out is None
